public class TwoPointers {

    // Two Sum II — sorted array, return 1-indexed positions
    public static int[] twoSum(int[] numbers, int target) {
        int left = 0, right = numbers.length - 1;

        while (left < right) {
            int sum = numbers[left] + numbers[right];
            if (sum == target)  return new int[]{left + 1, right + 1};
            if (sum < target)   left++;   // need bigger sum
            else                right--;  // need smaller sum
        }
        return new int[]{-1, -1}; // no solution
    }

    // Reverse an array in-place
    public static void reverse(int[] arr) {
        int left = 0, right = arr.length - 1;
        while (left < right) {
            int tmp    = arr[left];
            arr[left]  = arr[right];
            arr[right] = tmp;
            left++;
            right--;
        }
    }

    // Check palindrome
    public static boolean isPalindrome(String s) {
        int left = 0, right = s.length() - 1;
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) return false;
            left++;
            right--;
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15}, 9))); // [1, 2]
        System.out.println(isPalindrome("racecar")); // true
    }
}

public class SlidingWindowVariable {

    // Longest substring without repeating characters
    public static int lengthOfLongestSubstring(String s) {
        Map<Character, Integer> lastSeen = new HashMap<>();
        int left = 0, maxLen = 0;

        for (int right = 0; right < s.length(); right++) {
            char c = s.charAt(right);
            // If char already in window, shrink left past its last position
            if (lastSeen.containsKey(c) && lastSeen.get(c) >= left) {
                left = lastSeen.get(c) + 1;
            }
            lastSeen.put(c, right);
            maxLen = Math.max(maxLen, right - left + 1);
        }
        return maxLen;
    }

    // Minimum size subarray with sum >= target (positive numbers only)
    public static int minSubarrayLen(int target, int[] nums) {
        int left = 0, sum = 0, minLen = Integer.MAX_VALUE;

        for (int right = 0; right < nums.length; right++) {
            sum += nums[right];          // expand window
            while (sum >= target) {      // shrink while valid
                minLen = Math.min(minLen, right - left + 1);
                sum -= nums[left++];
            }
        }
        return minLen == Integer.MAX_VALUE ? 0 : minLen;
    }

    public static void main(String[] args) {
        System.out.println(lengthOfLongestSubstring("abcabcbb")); // 3 ("abc")
        System.out.println(minSubarrayLen(7, new int[]{2,3,1,2,4,3})); // 2 ([4,3])
    }
}
